// Format n8n error trigger data into a Slack alert
const wf_name = $json.workflow?.name || 'Unknown Workflow';
const wf_id = $json.workflow?.id || '';
const exec_id = $json.execution?.id || '';
const exec_url = $json.execution?.url || `$vars.N8N_HOST/workflow/${wf_id}/executions/${exec_id}`;
const error_msg = $json.execution?.error?.message || $json.trigger?.error?.message || 'Unknown error';
const error_node = $json.execution?.lastNodeExecuted || 'Unknown node';
const ts = new Date().toLocaleString('en-US',{timeZone:'America/Chicago',month:'short',day:'numeric',hour:'2-digit',minute:'2-digit'});

const blocks = [
  {"type":"header","text":{"type":"plain_text","text":"🚨 n8n Workflow Failed"}},
  {"type":"section","fields":[
    {"type":"mrkdwn","text":`*Workflow:* ${wf_name}`},
    {"type":"mrkdwn","text":`*Time:* ${ts} CST`},
    {"type":"mrkdwn","text":`*Failed Node:* ${error_node}`},
    {"type":"mrkdwn","text":`*Error:* ${error_msg.slice(0,200)}`}
  ]},
  {"type":"actions","elements":[
    {"type":"button","text":{"type":"plain_text","text":"View Execution"},"url":exec_url,"style":"danger"}
  ]}
];

return [{json:{blocks:JSON.stringify(blocks),wf_name,error_msg}}];
